// src/pages/Leave/LeavePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PENDING_HR: 'Pending HR',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
  DRAFT: 'Draft', Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
};

const STATUS_OPTIONS = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER','PENDINGHR','SUBMITTED','PENDING','DRAFT']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED'].includes(normStatus(s));

// Digs through all API envelopes to find the actual array
const toArr = (r) => {
  if (!r) return [];
  const d = r.data || r;
  if (Array.isArray(d)) return d;
  if (Array.isArray(d?.requests)) return d.requests;
  if (d?.data && Array.isArray(d.data)) return d.data;
  if (d?.data?.requests && Array.isArray(d.data.requests)) return d.data.requests;
  return [];
};

function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name = balance.leaveTypeName || balance.LeaveTypeName || balance.LeaveType?.LeaveTypeName || 'Leave';
  const used = Number(balance.usedDays ?? balance.UsedDays ?? 0);
  const pending = Number(balance.pendingDays ?? balance.PendingDays ?? 0);
  const entitled = Number(balance.entitledDays ?? balance.EntitledDays ?? 0);
  const carryOver = Number(balance.carryOverDays ?? balance.CarryOverDays ?? 0);
  const maxDays = entitled + carryOver;
  const remaining = Math.max(0, maxDays - used - pending);
  const pct = maxDays > 0 ? Math.round((remaining / maxDays) * 100) : 0;

  const color = name.includes('Sick') || name.includes('Medical') ? 'var(--green)' : 
                name.includes('Emergency') ? 'var(--red)' : 'var(--blue)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase' }}>{name}</div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}><div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} /></div>
      <div className="stat-card-meta"><span>{used} used {pending > 0 && `· ${pending} pending`}</span><span>{pct}%</span></div>
    </div>
  );
}

function RequestRow({ req, onAction, onEdit, isManager, isHR }) {
  const [acting, setActing] = useState('');
  const name = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.LeaveTypeName || '—';
  const from = (req.StartDate || req.startDate) ? new Date(req.StartDate || req.startDate).toLocaleDateString() : '—';
  const to = (req.EndDate || req.endDate) ? new Date(req.EndDate || req.endDate).toLocaleDateString() : '—';
  const days = req.TotalDays ?? req.totalDays ?? '—';
  const status = req.Status || req.status || 'SUBMITTED';
  const id = req.LeaveRequestID || req.id;
  const empName = req.Employee?.FullName || req.employeeName || '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal = isFinalStatus(status);

  return (
    <tr>
      <td><div style={{ fontWeight: 500 }}>{name}</div><div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{req.Reason || req.reason}</div></td>
      {isManager && <td><div style={{ fontWeight: 500 }}>{empName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{days}</td>
      <td>
        <span style={{
          display: 'inline-block', padding: '3px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 600,
          background: normStatus(status) === 'APPROVED' ? 'rgba(34,197,94,0.15)' : normStatus(status) === 'REJECTED' ? 'rgba(239,68,68,0.15)' : 'rgba(251,191,36,0.15)',
          color: normStatus(status) === 'APPROVED' ? '#16a34a' : normStatus(status) === 'REJECTED' ? '#dc2626' : '#b45309',
        }}>{STATUS_LABEL[status] || status}</span>
      </td>
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {isManager && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>{acting === 'approve' ? <InlineSpinner /> : 'Approve'}</button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>{acting === 'reject' ? <InlineSpinner /> : 'Reject'}</button>
            </>
          )}
          {isHR && isFinal && normStatus(status) !== 'CANCELLED' && (
            <button className="btn btn-ghost btn-sm" onClick={() => act(normStatus(status) === 'APPROVED' ? 'reject' : 'approve')} disabled={!!acting}><Shield size={13} style={{marginRight: 4}}/> Override</button>
          )}
          {!isManager && !isFinal && (
            <>
              {onEdit && <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)}><Edit3 size={14} /> Edit</button>}
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>{acting === 'cancel' ? <InlineSpinner /> : 'Cancel'}</button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '' });

  const handle = () => {
    if (!form.LeaveTypeID || !form.startDate || !form.endDate) return toast.error("Please fill all required fields");
    onSubmit({
      LeaveTypeID: parseInt(form.LeaveTypeID, 10),
      StartDate: new Date(form.startDate).toISOString(),
      EndDate: new Date(form.endDate).toISOString(),
      Reason: form.reason || null,
    });
  };

  return (
    <>
      <div className="form-group"><label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID} value={t.LeaveTypeID}>{t.LeaveTypeName}</option>)}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start Date</label><input className="form-input" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} /></div>
        <div className="form-group"><label className="form-label required">End Date</label><input className="form-input" type="date" value={form.endDate} min={form.startDate} onChange={e => setForm({...form, endDate: e.target.value})} /></div>
      </div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={2} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} /></div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 16 }}>
        <button className="btn btn-primary" onClick={handle} disabled={loading || !form.LeaveTypeID || !form.startDate || !form.endDate}>{loading ? <InlineSpinner /> : 'Submit Request'}</button>
      </div>
    </>
  );
}

export default function LeavePage() {
  const { user }  = useAuth();

  const roleStr = (user?.role || user?.Role || '').toUpperCase();
  const isManager = roleStr.includes('MANAGER') || roleStr.includes('HR') || roleStr.includes('ADMIN') || roleStr === 'SUPERVISOR';
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN');

  const [tab, setTab]             = useState('dashboard');
  const [balances, setBalances]   = useState([]);
  const [myRequests, setMyReqs]   = useState([]);
  const [allRequests, setAll]     = useState([]);
  const [leaveTypes, setTypes]    = useState([]);

  const [loadBal, setLoadBal]     = useState(true);
  const [loadReq, setLoadReq]     = useState(true);
  const [loadAll, setLoadAll]     = useState(true);

  const [submitting, setSubmitting] = useState(false);
  const [filter, setFilter] = useState('');
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [actingReason, setActingReason] = useState(false);
  const [reasonModal, setReasonModal] = useState(null); 
  const [editingRequest, setEditingRequest] = useState(null);

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).catch(console.warn).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).catch(console.warn).finally(() => setLoadReq(false));
    if (leaveAPI.getTypes) leaveAPI.getTypes().then(r => setTypes(toArr(r))).catch(() => {});

    if (isManager) {
      setLoadAll(true);
      leaveAPI.getManagerInbox ? leaveAPI.getManagerInbox().then(r => setAll(toArr(r))).catch(console.warn).finally(() => setLoadAll(false)) :
      leaveAPI.listAll().then(r => setAll(toArr(r))).catch(console.warn).finally(() => setLoadAll(false));
    } else { setLoadAll(false); }
  }, [isManager]);

  useEffect(() => { loadData(); }, [loadData]);

  const handleSubmit = async (form) => {
    setSubmitting(true);
    try {
      await leaveAPI.submit(form);
      toast.success('Leave request submitted!');
      setIsSubmitModalOpen(false);
      setTab('history');
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Submit Failed'); } 
    finally { setSubmitting(false); }
  };

  const handleUpdate = async (form) => {
    setSubmitting(true);
    try {
      await leaveAPI.updateRequest(editingRequest.LeaveRequestID || editingRequest.id, form);
      toast.success('Request updated!');
      setEditingRequest(null);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Update Failed'); } 
    finally { setSubmitting(false); }
  };

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'cancel') {
        if (!reason) { setReasonModal({ id, action: 'cancel' }); return; }
        await leaveAPI.cancel(id, { CancelReason: reason });
        toast.success('Request cancelled');
      } else if (action === 'approve') {
        await leaveAPI.approveReject(id, { decision: 'APPROVED', comments: '' });
        toast.success('Request approved');
      } else if (action === 'reject') {
        if (!reason) { setReasonModal({ id, action: 'reject' }); return; }
        await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: reason });
        toast.success('Request rejected');
      }
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Action failed'); }
  };

  const handleReasonConfirm = async (reason) => {
    setActingReason(true);
    try {
      await handleAction(reasonModal.id, reasonModal.action, reason);
      setReasonModal(null);
    } finally { setActingReason(false); }
  };

  const handlePayrollSync = async () => {
    try {
      const period = { periodYear: new Date().getFullYear(), periodMonth: new Date().getMonth() + 1 };
      const res = await leaveAPI.syncPayroll(period);
      toast.success(`Synced ${res.data?.data?.syncedCount || 'records'} to payroll`);
    } catch (err) { toast.error("Payroll sync failed"); }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard',    icon: BarChart2 },
    { id: 'history',   label: 'My History',   icon: Clock },
    ...(isManager ? [ { id: 'all', label: isHR ? 'All Requests' : 'Team Inbox', icon: Users } ] : []),
    ...(isHR ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  return (
    <>
      {reasonModal && (
        <Modal title={reasonModal.action === 'cancel' ? 'Cancel Request' : 'Reject Request'} onClose={() => setReasonModal(null)}>
          <textarea className="form-textarea" onChange={e => reasonModal.reason = e.target.value} placeholder="Enter reason..." rows={3} />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 10 }}>
            <button className="btn btn-primary" onClick={() => handleReasonConfirm(reasonModal.reason)} disabled={actingReason}>{actingReason ? <InlineSpinner /> : 'Confirm'}</button>
          </div>
        </Modal>
      )}

      {editingRequest && (
        <Modal title="Edit Leave Request" onClose={() => setEditingRequest(null)}>
           <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleUpdate} loading={submitting} />
        </Modal>
      )}

      {isSubmitModalOpen && (
        <Modal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
          <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} />
        </Modal>
      )}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Manage leave requests, balances, and approvals</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18} style={{ marginRight: 8, verticalAlign: 'middle' }} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{ marginRight: 6, verticalAlign: 'middle' }} />{label}</button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && (
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal ? <SkeletonCard /> : balances.map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)}
          </div>
        )}

        {tab === 'history' && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">My Leave History</div>
              <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
            </div>
            {loadReq ? <SkeletonCard /> : myRequests.length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                  <tbody>{myRequests.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onEdit={setEditingRequest} isManager={false} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'all' && isManager && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">{isHR ? 'Company-Wide Leaves' : 'Team Pending Approvals'}</div>
              <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
            </div>
            {loadAll ? <SkeletonCard /> : allRequests.length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                  <tbody>{allRequests.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} isManager={true} isHR={isHR} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'settings' && isHR && (
          <div className="grid-2">
             <div className="card">
               <div className="card-header"><div className="card-title"><ArrowRightLeft size={16} style={{marginRight:6}}/> Payroll Integration (LV-044)</div></div>
               <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 16 }}>Synchronize all approved leave records with the payroll module to apply unpaid leave deductions and sickness tiers.</p>
               <button className="btn btn-primary" onClick={handlePayrollSync}><RefreshCw size={14} style={{marginRight:6}}/> Sync to Payroll</button>
             </div>
             <div className="card">
                <div className="card-header"><div className="card-title"><Shield size={16} style={{marginRight:6}}/> System Integrity</div></div>
                <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>You can override approved or rejected requests directly from the 'All Requests' tab using the Override button.</p>
             </div>
          </div>
        )}
      </div>
    </>
  );
}
